import fs from 'node:fs';
import path from 'node:path';
import { gzipSync } from 'node:zlib';
import { fileURLToPath } from 'node:url';

// Converts dist/index.html (Vite single-file build output) into
// ../wled00/web_ui_bundle.h — a gzipped byte array the firmware HTTP route
// serves at GET /.

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const WEB_UI_ROOT = path.resolve(__dirname, '..');
const SRC = path.join(WEB_UI_ROOT, 'dist', 'index.html');
const OUT = path.resolve(WEB_UI_ROOT, '..', 'wled00', 'web_ui_bundle.h');

if (!fs.existsSync(SRC)) {
  console.error(`[bundle-to-header] missing ${SRC} — run 'vite build' first`);
  process.exit(1);
}

const raw = fs.readFileSync(SRC);
const gz = gzipSync(raw, { level: 9 });
const kb = (n) => (n / 1024).toFixed(1);

console.log(`[bundle-to-header] raw=${kb(raw.length)} KB · gzip=${kb(gz.length)} KB · target<=80 KB`);
if (gz.length > 80 * 1024) {
  console.warn(`[bundle-to-header] WARNING: bundle exceeds 80 KB gzip budget`);
}

const rows = [];
for (let i = 0; i < gz.length; i += 16) {
  rows.push(
    '  ' +
      Array.from(gz.subarray(i, i + 16))
        .map((b) => '0x' + b.toString(16).padStart(2, '0'))
        .join(', '),
  );
}

const header = [
  '// AUTO-GENERATED by web-ui/scripts/bundle-to-header.js — do not edit.',
  '#pragma once',
  '',
  '#include <pgmspace.h>',
  '#include <stddef.h>',
  '#include <stdint.h>',
  '',
  `const size_t  web_ui_bundle_len = ${gz.length};`,
  'const uint8_t web_ui_bundle[] PROGMEM = {',
  rows.join(',\n'),
  '};',
  '',
].join('\n');

fs.writeFileSync(OUT, header);
console.log(`[bundle-to-header] wrote ${OUT}`);
